{"code":"import requests
import pandas as pd
from requests_toolbelt.multipart.encoder import MultipartEncoder
from io import StringIO

def _get_num_matches(db, mzStr, adducts, tolerance=0.001):
    url = 'https://www.lipidmaps.org/tools/ms/bulk_search_check.php'

    # Prepare the multipart form data
    m = MultipartEncoder(
        fields={
            'database': db,
            'input_type': 'mz',
            'mz_list': mzStr,
            'adducts': adducts,
            'tolerance': str(tolerance),
            'output_format': 'text'
        }
    )

    response = requests.post(url, data=m, headers={'Content-Type': m.content_type})

    if response.status_code != 200:
        return 0

    # The response is usually a tab-separated text or CSV
    # We need to parse it to find which input m/z values had matches.
    # LipidMaps bulk search results usually include the input m/z.
    try:
        df = pd.read_csv(StringIO(response.text), sep='\t')
        if df.empty:
            return 0
        # The column name for input m/z might vary, but often it's 'Input m/z' or similar.
        # Let's look for a column that contains the input values.
        # If the search returns matches, we count unique input m/z values.
        # Based on LipidMaps MS search output, 'Input m/z' is a common header.
        if 'Input m/z' in df.columns:
            return df['Input m/z'].nunique()
        else:
            # Fallback: if we can't find the column, maybe the first column is the input m/z
            return df.iloc[:, 0].nunique()
    except:
        return 0

def main():
    db = 'GLYCOLIPIDS'
    mz_values = '100.0\n200.0\n300.0'
    adducts = 'M+H,M+Na'
    tolerance = 0.01
    num_matches = _get_num_matches(db, mz_values, adducts, tolerance)
    print(f'Number of unique m/z matches: {num_matches}')

if __name__ == '__main__':
    main()
"}
